func:
// 讀取每日歷史、今日統計、排除日期、基線設定天數，組成 /api/deviation 的請求 body。
// 對應 Python 端：cat_monitoring_system/server/routes.py -> POST /api/deviation
//                 cat_monitoring_system/analytics/README.md 有完整設計說明
//
// 可從兩個地方觸發：
//   1. 手動測試 inject 節點（本 tab 內建）
//   2. link in 節點——若要接到既有 cat_health_v3_flow.json 的即時流程，
//      在該 flow 裡「行為統計累積器」之後加一個 link out，
//      target 指到本節點對應的 link in（id 需自行對應）。
//
// 已知問題：v2_daily_history 裡的 date 欄位可能是 ISO（YYYY-MM-DD）或
// toLocaleDateString('zh-TW') 產生的本地格式（例如 2026/7/2，甚至混雜
// 「2026/6/2 下午10:30:32」這種帶時分秒的格式——對應 behavior_segments_log.csv
// 已知的日期混用 bug）。/api/deviation 對日期格式很嚴格（只收 ISO），
// 這裡會盡量正規化，無法辨識的直接跳過並記警告，避免一筆髒資料讓整批請求失敗。

function toISODate(raw) {
    if (raw == null) return null;
    let s = String(raw).trim();
    if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
    let m = s.match(/^(\d{4})\/(\d{1,2})\/(\d{1,2})/);
    if (m) {
        let y = m[1], mo = m[2].padStart(2, '0'), d = m[3].padStart(2, '0');
        return y + '-' + mo + '-' + d;
    }
    return null;
}

let history = global.get('v2_daily_history', 'file') || [];
let skipped = 0;
let dailyHistory = [];
for (let d of history) {
    let iso = toISODate(d.date);
    if (!iso) { skipped++; continue; }
    dailyHistory.push({
        date: iso,
        monitoring_seconds: d.monitoring_seconds || 0,
        walk_time: d.walk_time || 0, walk_count: d.walk_count || 0,
        stop_time: d.stop_time || 0, stop_count: d.stop_count || 0,
        lick_time: d.lick_time || 0, lick_count: d.lick_count || 0,
        scratch_time: d.scratch_time || 0, scratch_count: d.scratch_count || 0,
        shake_count: d.shake_count || 0,
        active_time: d.active_time || 0, rest_time: d.rest_time || 0,
    });
}
if (skipped > 0) {
    node.warn('組成 /api/deviation 請求：略過 ' + skipped + ' 筆無法辨識日期格式的歷史紀錄（見 behavior_segments_log.csv 已知的日期混用 bug）');
}

// today：優先用 msg.payload.v2_today（若由既有 flow 的 msg 鏈接進來），
// 否則退回 global 的 v2_today（若有另外用 global.set 存過的話）。
let td = (msg.payload && msg.payload.v2_today) || global.get('v2_today') || {};
let today = {
    walk_time:     (td.walk     && td.walk.time)     || 0,
    lick_time:     (td.lick     && td.lick.time)      || 0,
    lick_count:    (td.lick     && td.lick.count)     || 0,
    scratch_time:  (td.scratch  && td.scratch.time)   || 0,
    scratch_count: (td.scratch  && td.scratch.count)  || 0,
    shake_count:   (td.shake    && td.shake.count)    || 0,
    stop_time:     (td.stop     && td.stop.time)      || 0,
};

let cfg = global.get('v2_user_settings', 'file') || {};
let minBaselineDays = cfg.baseline_days != null ? +cfg.baseline_days : 7;
let excludedDates = (global.get('v2_excluded_dates', 'file') || []).map(toISODate).filter(Boolean);

let pythonIp = global.get('python_ip');
if (!pythonIp) {
    node.warn('/api/deviation 橋接：global.python_ip 尚未設定（Python 端可能還沒送過 /python_online 上線通知），中止本次請求。');
    return null;
}

msg.url = 'http://' + pythonIp + ':5000/api/deviation';
msg.payload = {
    daily_history: dailyHistory,
    today: today,
    excluded_dates: excludedDates,
    min_baseline_days: minBaselineDays,
    // Class C（節律/轉移模式）尚未搬遷到 Python，見 analytics/README.md「還沒做的事」。
    // 暫時預設 0；若既有 flow 已算出節律/轉移分數並存到 global.v2_class_c_score，
    // 這裡會自動帶入。
    class_c_score: global.get('v2_class_c_score') || 0,
};
return msg;

// 比對模式（安全，不覆蓋正式資料）：
// 把 /api/deviation 的回應寫進「_py」結尾的獨立 global 變數
// （v2_baseline_py / v2_deviation_py / v2_risk_py / v2_baseline_alert_py /
// v2_baseline_insufficient_py），不會動到 cat_health_v3_flow.json 自己
// 的「個體化基線計算器」「偏差分析引擎」「行為偏差融合引擎」持續在寫的
// v2_baseline / v2_deviation / v2_risk。兩邊可以同時跑，互不干擾，方便
// 直接比對新舊引擎的數字（見「比對新舊引擎結果」節點）。
//
// 等確認 Python 版數字沒問題、決定要正式切換時，再把這裡的 key 改回
// 不帶 _py 的原始名稱，並停用/移除 cat_health_v3_flow.json 裡的舊引擎節點。
//
// 已知限制：analytics/fusion.py 目前只算 level / score / class_a / class_b /
// class_c / top_contributors，沒有算舊版 JS 裡完整的 xai_explanation 解釋
// 文字，也沒有 alerts 陣列裡逐條格式化的警報訊息——這些屬於展示邏輯，
// 尚未搬遷（見 analytics/README.md）。color/emoji/status 文字在這裡用
// 簡單規則補上，方便比對時直接看得懂。

if (msg.statusCode !== 200 || !msg.payload) {
    node.warn('/api/deviation 呼叫失敗，statusCode=' + msg.statusCode + '，本次不更新 _py 比對資料。');
    return null;
}

let body = msg.payload;

if (body.status === 'insufficient_data') {
    let alertMsg = '歷史資料不足（' + body.current_days + ' 天），尚需 ' +
        Math.max(0, body.required_days - body.current_days) + ' 天才能建立基線。';
    global.set('v2_baseline_alert_py', alertMsg);
    global.set('v2_baseline_insufficient_py', true);
    node.warn(alertMsg);
    msg.payload = { status: 'insufficient_data', current_days: body.current_days, required_days: body.required_days };
    return msg;
}

if (body.status !== 'ok') {
    node.warn('/api/deviation 回傳未知狀態: ' + JSON.stringify(body).slice(0, 200));
    return null;
}

global.set('v2_baseline_insufficient_py', false);
global.set('v2_baseline_py', body.baseline, 'file');
global.set('v2_deviation_py', body.deviation);

const LEVEL_STYLE = {
    'Normal':                        { color: '#4caf50', emoji: '✅', status: '行為正常' },
    'Mild Behavioral Deviation':     { color: '#ffa726', emoji: '⚠️', status: '輕度行為偏差' },
    'Moderate Behavioral Deviation': { color: '#ff7043', emoji: '🚨', status: '中度行為偏差' },
    'Severe Behavioral Deviation':   { color: '#f44336', emoji: '🆘', status: '重度行為偏差' },
};
let style = LEVEL_STYLE[body.fusion.level] || { color: '#9e9e9e', emoji: '❔', status: body.fusion.level };

let riskPy = {
    behavior_deviation_score: body.fusion.score,
    behavior_status: style.status,
    behavior_deviation_level: body.fusion.level,
    score: body.fusion.score, level: body.fusion.level,
    color: style.color, emoji: style.emoji,
    components: {
        class_a: body.fusion.class_a_score,
        class_b: body.fusion.class_b_score,
        class_c: body.fusion.class_c_score,
    },
    class_a_triggered: body.fusion.class_a_triggered,
    class_a_override: body.fusion.class_a_override,
    top_contributors: body.fusion.top_contributors,
    confidence: body.baseline.confidence,
    engine: 'python_analytics_bridge',
    computed_at: new Date().toISOString(),
};
global.set('v2_risk_py', riskPy);

msg.payload = { status: 'ok', baseline: body.baseline, deviation: body.deviation, risk: riskPy };
return msg;

// 比對新舊引擎：讀取 cat_health_v3_flow.json 舊引擎寫的 global.v2_risk
// 跟本橋接流程寫的 global.v2_risk_py，整理成一份精簡對照，方便直接看
// 兩邊算出來的 level/score 是否一致、差在哪裡——這是驗證 Python 版
// 偏差引擎是否可信的關鍵步驟，不是可有可無的展示。

let oldRisk = global.get('v2_risk')    || null;
let newRisk = global.get('v2_risk_py') || null;

let comparison = {
    old_engine: oldRisk ? {
        level: oldRisk.level, score: oldRisk.score,
        class_a_triggered: oldRisk.class_a_triggered,
    } : '（尚無資料，cat_health_v3_flow.json 的行為偏差融合引擎還沒算過）',
    new_engine: newRisk ? {
        level: newRisk.level, score: newRisk.score,
        class_a_triggered: newRisk.class_a_triggered,
        top_contributors: newRisk.top_contributors,
    } : '（尚無資料，見上方警告）',
};

if (oldRisk && newRisk) {
    comparison.level_match = (oldRisk.level === newRisk.level);
    comparison.score_diff  = +(newRisk.score - oldRisk.score).toFixed(1);
    if (!comparison.level_match) {
        node.warn('⚠ 新舊引擎判斷等級不同： 舊=' + oldRisk.level + ' 新=' + newRisk.level + '（score 差 ' + comparison.score_diff + '）');
    }
}
comparison.compared_at = new Date().toLocaleString('zh-TW');

msg.payload = comparison;
return msg;
